  pointer-events: none;
}

.hero-eyebrow {
  font-size: 14px;
  font-weight: 700;
  color: rgba(255,255,255,1);
  letter-spacing: .2em;
  text-transform: uppercase;
  margin-bottom: 20px;
  position: relative;
}

.hero-title {
  font-size: clamp(36px, 5.5vw, 56px);
  font-weight: 900;
  line-height: 1.3;
  letter-spacing: -1.5px;
  margin-bottom: 12px;
  position: relative;
  color: var(--accent-yellow);
}

.hero-subtitle {
  font-size: clamp(29px, 4.4vw, 45px);
  font-weight: 700;
  line-height: 1.3;
  letter-spacing: -0.5px;
  margin-bottom: 16px;
  position: relative;
  color: #ffffff;
}

.hero-desc {
  font-size: 17px;
  color: #ffffff;
  line-height: 1.8;
  max-width: 800px;
  margin: 0 auto;
  position: relative;
}

/* Framework Intro Section */
.framework-intro {
  padding: 0 48px;
  margin-top: -30px;
  margin-bottom: 80px;
  position: relative;
  z-index: 10;
  display: flex;
  justify-content: center;
}

/* VIBE Modal (for framework card) */
.vibe-modal {
  display: none;
  position: fixed;
  z-index: 1000;
  left: 0;
  top: 0;
  width: 100%;
  height: 100%;
  background-color: rgba(0,0,0,0.75);
  backdrop-filter: blur(10px);
}

.vibe-modal.active {
  display: flex;
  align-items: center;
  justify-content: center;
  animation: fadeIn 0.3s ease;
}

.vibe-modal-content {
  background: #fff;
  padding: 60px;
  border-radius: 24px;
  max-width: 1400px;
  max-height: 90vh;
  overflow-y: auto;
  box-shadow: 0 24px 80px rgba(0,0,0,.4);
