.phase-btn{background:none;border:2px solid #E5E7EB;border-radius:16px;padding:16px 24px;cursor:pointer;transition:all .25s;text-align:center;min-width:140px}
.phase-btn.active{border-color:var(--red);background:var(--red-light)}
.phase-circle{width:36px;height:36px;border-radius:50%;background:#E5E7EB;color:#6B7280;font-size:16px;font-weight:700;display:flex;align-items:center;justify-content:center;margin:0 auto 8px}
.phase-btn.active .phase-circle{background:var(--red);color:#fff}
.phase-label{font-size:13px;font-weight:600;color:#374151;line-height:1.4}
.phase-date{font-size:12px;color:#9CA3AF;margin-top:4px}
.phase-content{display:none}
.phase-content.active{display:block}
```

```js
function showPhase(n) {
  document.querySelectorAll('.phase-btn').forEach((btn, i) => {
    btn.classList.toggle('active', i === n - 1);
  });
  document.querySelectorAll('.phase-content').forEach(c => {
    c.classList.remove('active');
  });
  document.getElementById(`phase-${n}`).classList.add('active');
}
```

